pub(crate) const GG_TEAM_MANAGE_BASE_DESCRIPTION: &str = "Manage team membership. Provide `remove_agent_ids` (array format, for example [\"agent_1\", \"agent_2\"]) to remove existing members. Omit `remove_agent_ids` to add one member with optional `title`, optional `prompt`, optional `image_paths`, optional `model_preset`, optional `creator_compaction_subscription`, optional `worktree_name`, and optional `use_existing_worktree`. For add calls, onboarding instructions from `prompt` are delivered as a canonical direct TeamMessage to the spawned member. `creator_compaction_subscription` defaults to `auto`; set `unsubscribed` to suppress creator-recipient compaction notices for the new member. When `worktree_name` is provided, native branch/worktree/cwd derivation is runtime-owned and `pre_teammate_add` hook `spawn_template_mutation.cwd` is ignored. `post_teammate_remove` hooks run for both `agent_tool` and `ui_command` removals.";
pub(crate) const GG_MCP_CALLER_AGENT_ID_ARG_KEY: &str = "__gg_caller_agent_id";
